V su(V a,V b){return mk(a.x-b.x,a.y-b.y,a.z-b.z);}
V ml(V a,float t){return mk(a.x*t,a.y*t,a.z*t);}
float dt(V a,V b){return a.x*b.x+a.y*b.y+a.z*b.z;

}
V nm(V v){float l=sqrtf(dt(v,v));return mk(v.x/l,v.y/l,v.z/l);}
#define W 2400
#define H 1800
V cam={0,-.5f,-5.f};
V sc={0,0,0};
float sr=1.f,py=-1.5f;
V ld;
float hs(V ro,V rd){V oc=su(ro,sc);float b=dt(oc,rd),c=dt(oc,oc)-sr*sr,h=b*b-c;return h<0?-1:-b-sqrtf(h);}
float hp(V ro,V rd){if(fabsf(rd.y)<1e-6f)return-1;float t=(py

-ro.y)/rd.y;return t>0?t:-1;}
V tr(V ro,V rd){
    float ts=hs(ro,rd),tp=hp(ro,rd),t;int h1=0,h2=0;
    if(ts>0&&tp>0){if(ts<tp){t=ts;h1=1;}else{t=tp;h2=1;}}
    else if(ts>0){t=ts;h1=1;}
    else if(tp>0){t=tp;h2=1;}
    else{V n=nm(rd);float a=.5f*(n.y+1.f);return ad(ml(mk(1,1,1),1.f-a),ml(mk(.5f,.7f,1.f),

a));}
    V pos=ad(ro,ml(rd,t)),N;
    V color;
    if(h1){N=nm(su(pos,sc));color=mk(1.f,.2f,.2f);}
    else{N=mk(0,1,0);
    double fx=floor((double)pos.x),fz=floor((double)pos.z);
    int s=((int)(fx+fz))&1;
    float ck=s?.4f:.9f;color=mk(ck,ck,ck);}
    float diff=fmaxf(dt(N,ld),0.f);
    V so=ad(pos,ml(N,.001f));
    if(hs(so,ld)>.001f)diff=0;
    return

 ml(color,.2f+.8f*diff);
}
int main(){
    ld=nm(mk(-1.f,1.f,1.f));
    FILE*f=fopen("reconstructed.ppm","w");
    fprintf(f,"P3\n%d %d\n255\n",W,H);
    float vw=2.f*W/H;
    float vh=1.f;
    V vU=mk(vw,0,0);
    V vV=mk(0,vh,0);
    V w=mk(0,0,vh);
    V ll=ad(su(su(cam,ml(vU,.5f)),ml(vV,.5f)),

w);
    for(int j=0;j<H;j++){
        float v=1.f-(float)j/(H-1);
        for(int i=0;i<W;i++){
            float u=(float)i/(W-1);
            V tgt=ad(ad(ll,ml(vU,u)),ml(vV,v));
            V rd=nm(su(tgt,cam));
            V c=tr(cam,rd);
            int r=(int)(fminf(c.x,1.f)*255.99f),g=(int)(fminf(c.y,1.f)*255.99f),b=(int)(fminf(c.z,1.f)*255.99f);
            fprintf(f,"%d %d %d\n",r,g,b);\

n        }\n    }\n    fclose(f);return 0;\n}\nCEOF\n",
      "duration": 1.0
    },
    {
      "keystrokes": "gcc -static -o image image.c -lm 2>&1 && ./image && python3 compare.py\n",
      "duration": 180.0
    }
  ],
  "task_complete": false
}

